1	export type Cell = [number, number];
2	
3	function isNeighbor(a: Cell, b: Cell): boolean {
4	  const [ax, ay] = a;
5	  const [bx, by] = b;
6	  if (ax === bx && ay === by) return false;
7	  return Math.abs(ax - bx) <= 1 && Math.abs(ay - by) <= 1;
8	}
9	
10	function countLiveNeighbors(cell: Cell, cells: Cell[]): number {
11	  return cells.filter((other) => isNeighbor(cell, other)).length;
12	}
13	
14	export function nextGeneration(cells: Cell[]): Cell[] {
15	  return cells.filter((cell) => countLiveNeighbors(cell, cells) === 2);
16	}
