export function nextGeneration(cells: Cell[]): Cell[] {
  const survivors = cells.filter((cell) => countLiveNeighbors(cell, cells) === 2);
  const candidates: Cell[] = [];
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const candidate: Cell = [x + dx, y + dy];
        const isLive = cells.some(([cx, cy]) => cx === candidate[0] && cy === candidate[1]);
        if (isLive) continue;
        const alreadyAdded = candidates.some(([cx, cy]) => cx === candidate[0] && cy === candidate[1]);
        if (alreadyAdded) continue;
        if (countLiveNeighbors(candidate, cells) === 3) {
          candidates.push(candidate);
        }
      }
    }
  }
  return [...survivors, ...candidates];
}
